(window.webpackJsonp=window.webpackJsonp||[]).push([[347],{974:function(n,e){n.exports='\x3c!-- \ntitle: 06-Vue路由\nsort: \n--\x3e \n\n```js\n// 定义路由\nvar routes = [\n  {\n    path: \'/\',\n    component: {\n      template: \'#home\',\n    },\n  },\n  {\n    path: \'/about\',\n    component: {\n      template: \'#about\',\n    },\n  },\n  {\n    path: \'/user/:name\',\n    component: {\n      template: \'#user\',\n    },\n  },\n];\n// 绑定路由\nvar router = new VueRouter({\n  routes: routes,\n});\n\nnew Vue({\n  el: \'#app\',\n  router: router,\n});\n\n// html\n<div id="app">\n  <div>\n    <router-link to="/">Home</router-link>\n    <router-link to="/about">About</router-link>\n    <router-link to="/user/1">user·1</router-link>\n    <router-link to="/user/2">user·2</router-link>\n  </div>\n  <div>\n    <router-view></router-view>\n  </div>\n</div>\n<template id="home">\n  <div>\n    <h1>Home</h1>\n  </div>\n</template>\n<template id="about">\n  <div>\n    <h1>About</h1>\n  </div>\n</template>\n<template id="user">\n  <div>\n    <div>Name: {{$route.params.name}}</div>\n    <div>Age: {{$route.query.age}}</div>\n  </div>\n</template>\n```\n\n'}}]);